function primesSieve(start, end) {
  if (end < 2) return [];
  const sieve = new Uint8Array(end + 1).fill(1);
  sieve[0] = sieve[1] = 0;
  for (let i = 2; i * i <= end; i++) {
    if (sieve[i]) {
      for (let j = i * i; j <= end; j += i) sieve[j] = 0;
    }
  }
  return Array.from({ length: end - start + 1 }, (_, i) =>
    sieve[start + i] ? start + i : null
  ).filter(Boolean);
}

function primesTrial(start, end) {
  const primes = [];
  for (let num = Math.max(2, start); num <= end; num++) {
    let isPrime = true;
    for (let i = 2; i * i <= num; i++) {
      if (num % i === 0) { isPrime = false; break; }
    }
    if (isPrime) primes.push(num);
  }
  return primes;
}
